            ContentJson = """{"appRoute":"/vendors","startButtonLabel":"Tour Vendors","steps":[{"element":"[data-testid='new-vendor-btn']","popover":{"title":"New Vendor Button","description":"Click here to create a new vendor. This opens a fork dialog where you choose how to set up the vendor: Quick add (flat dialog — just company name and basic contact, flesh out the rest later) or Guided setup (a step-by-step wizard at /vendors/new for strategic or approved vendors — classification, address, terms, and the parts they supply). The rest of this tour covers the Quick add dialog.","side":"bottom"}},{"element":".filters-bar app-input","popover":{"title":"Search Vendors","description":"Search vendors by company name, contact name, email, or phone number. Just type — the list filters automatically a moment after you stop typing (a short debounce); pressing Enter applies it immediately. Results update based on matching text across all searchable fields.","side":"bottom"}},{"element":".filters-bar app-select","popover":{"title":"Status Filter","description":"Filter vendors by active status: All (show everything), Active (currently doing business with), or Inactive (deactivated vendors). Inactive vendors are preserved for history but won't appear in PO vendor dropdowns.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Vendors Table","description":"The table shows all vendors matching your current filters. Columns include Company Name, Contact, Email, Phone, Active status (green/gray chip), PO count, and Created date. Click any column header to sort. Click any row to open the vendor detail dialog.","side":"top"}},{"element":"app-data-table thead th:nth-child(6)","popover":{"title":"PO Count Column","description":"Shows how many purchase orders have been placed with each vendor. This gives you a quick sense of how frequently you order from a supplier without opening the detail view.","side":"bottom"}}]}"""
