            Tags = """["vendors","quiz","procurement"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"vn1","text":"You need to onboard a new raw material supplier before placing your first purchase order. What is the correct first step?","options":[{"id":"a","text":"Go to Purchase Orders and create a PO — the vendor will be auto-created"},{"id":"b","text":"Navigate to Vendors, click New Vendor, then pick a setup path (Quick add or Guided setup) and fill in at least the company name","isCorrect":true},{"id":"c","text":"Add the supplier to Inventory as a new storage location"},{"id":"d","text":"Go to Admin → Reference Data and add the vendor as a lookup value"}],"explanation":"New suppliers must be created in the Vendors module first. Click New Vendor in the page header — this opens a fork where you choose Quick add (a flat dialog needing only the company name to start) or Guided setup (a step-by-step wizard for strategic or approved vendors). Either way, the only required field is Company Name; the vendor then becomes available in PO vendor dropdowns."},{"id":"vn2","text":"Which field is the only required field when creating a new vendor?","options":[{"id":"a","text":"Contact Name"},{"id":"b","text":"Email"},{"id":"c","text":"Company Name","isCorrect":true},{"id":"d","text":"Payment Terms"}],"explanation":"Company Name is the only required field on the vendor form. All other fields — contact name, email, phone, address, payment terms, and notes — are optional."},{"id":"vn3","text":"A vendor's scorecard shows a grade of 'C' with an overall score of 68/100. What does this tell you?","options":[{"id":"a","text":"The vendor has been deactivated due to poor performance"},{"id":"b","text":"The vendor is performing below average based on weighted criteria: delivery (40%), quality (30%), price (20%), and quantity accuracy (10%)","isCorrect":true},{"id":"c","text":"The vendor has only completed a few POs and doesn't have enough data