            AppRoutes = """["/vendors"]""",
            Tags = """["vendors","catalog","avl","walkthrough","procurement"]""",
            ContentJson = """{"appRoute":"/vendors","startButtonLabel":"Tour the Catalog Tab","steps":[{"element":"app-data-table","popover":{"title":"Open a Vendor","description":"Start on the Vendors list and click any vendor row to open its detail panel. The detail panel has the tabs we'll use next — Info, Purchase Orders, Catalog, and Scorecard.","side":"top"}},{"element":"[data-testid='vendor-tab-catalog']","popover":{"title":"Catalog Tab","description":"Click the Catalog tab to see the parts this vendor supplies. Each row is a vendor-part: the linked part, the vendor's part number, lead time, MOQ, pack size, lowest price tier, and the Approved (AVL) flag. This is the same relationship you'd see on a Part's Sources tab, viewed from the vendor's side.","side":"bottom"}},{"element":"[data-testid='vendor-part-add-btn']","popover":{"title":"Add a Supplied Part","description":"Click + Add to record a new part this vendor supplies. The vendor is locked (you're inside it), so you pick the Part and fill in vendor-scoped fields: vendor part number, lead time, MOQ, pack size, country of origin, and the Approved and Preferred toggles.","side":"bottom"}},{"element":"[data-testid='vendor-part-import-btn']","popover":{"title":"Bulk CSV Import","description":"For a whole catalog or price list, click Import. Drag in a .csv (a Download Template link gives you the exact columns), then review the preview — every row is tagged Add, Update, or Error. Fix any flagged errors, then Apply to commit the adds and updates in one pass.","side":"bottom"}}]}"""
